import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.9.资源与本质","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/1.核心规则/1.9.资源与本质.md","filePath":"1.基础规则/1.核心规则/1.9.资源与本质.md"}'),s={name:"1.基础规则/1.核心规则/1.9.资源与本质.md"};function o(_,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"_1-9-资源与本质",tabindex:"-1"},[b("1.9.资源与本质 "),r("a",{class:"header-anchor",href:"#_1-9-资源与本质","aria-label":'Permalink to "1.9.资源与本质"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),n('<h1 id="资源与本质" tabindex="-1">资源与本质 <a class="header-anchor" href="#资源与本质" aria-label="Permalink to &quot;资源与本质&quot;">​</a></h1><p>资源种类：<br> 一般而言，资源被大致分为内在和外在两种。<br> 内在资源一般包括【血统/训练】、【改造/功法】、【能量】、【技艺/称号】、【见证强化】，它们的共同特点是会提供额外的自由属性。<br> 外在资源一般包括【武器】、【防具】、【载具】、【奇物】、【物品】等，它们的共同点是属于人物的身外之物，有可能被击毁、剥夺。</p><p>内在强化会提供自由属性点</p><p>D级内在强化提供2属性点<br> C级内在强化提供4属性点<br> B级内在强化提供8属性点<br> A级内在强化提供16属性点<br> S级内在强化提供32属性点</p><p>最高内在强化支线等级：<br> 最高内在强化支线等级是指某角色拥有的内在强化中，等级最高的一种对应的等级。<br> （例：玩家愚者拥有忍义手（D级）、苇名流（C级）、魔刀千刃（B级），那么此时他的最高内在强化支线等级是C）</p><p>洗点与换购/出售规则：<br> 一位轮回者每经过三场影片最多可以洗点一次，在主神空间中花费D+500购买洗点水，选择自身拥有的X项内在强化放弃，所有内在强化提供的效果和属性全部失去，返还这些强化总价格的7成。<br> 洗点时，若某资源是可升级资源，则必须从最高级开始洗，有购买前置条件的资源同理。<br> 轮回者也可以将在主神空间处购买的外在资源以换购/出售的形式返还给主神空间，换购规则为将外在资源返还，并选择一项可被购买的，价格不超过该资源7成的外在资源获得，也可以换购更高价格的外在资源，此时被换购的资源视为充当了其原价7成的价格。出售则一次性获得该资源7成的价格。</p><p>本质类型：<br> 本质一般是对于外在资源的划分和定类，本质分为自然、科技、神话、特异、魔法五种。</p><p>●自然本质<br> 具有“自然”这一本质作为描述的事物是现实中天然所具有、或是经过少量人工加工，不需要电气化设备参与，只凭简单的随手工具即可再现的事物。<br> 绝大多数被描述为“自然”的事物都拥有在现实中可以理解、推测或实现的应对方法。例如，自然的毒素效果，时常可以用草药或偏方来解除。<br> 至少在理论上，轮回小队成员可以在自己的个人空间内生成自然的物品、事物或效果，但如果它们以非天然的方式存在，则会依其自然规律而枯萎消蚀。<br> 自然描述的范例包括蛇毒、矿物毒、草药、动物的低光视觉能力等。</p><p>●科技本质<br> 具有“科技”这一本质作为描述的事物是借助科学技术所构成、可以达成某种效果的工具或消耗品，它们可以被完全或部分地以科学理论进行解释。拥有这一本质的必然是某种物品，可以是工具或者消耗品。<br> 某些效果可以使具有“科技”描述的工具失去效果，有时这一效果不会使工具完全失效，而是使其效用退化到较低技术含量的同类物品的水准。例如，动力装甲会变得如同歌特甲一般。<br> 科技描述的范例包括了所有现实中常见的工具，以及盖塔能源炉、GGGG等</p><p>●神话本质<br> 具有“神话”这一本质作为描述的事物是只被记述在神话故事之中的物品，它们在现实世界中并不存在，或原本可能存在，但经过人类的口耳相传、神话故事的进一步演绎后脱离了原本形态。<br> 神话并不仅局限于一地的神话，甚至可以是其他星球、其他位面、其他文明的神话，它们都用一个共同点，即被广泛传播，经过重重演绎，被赋予了新的意志和神性，而传播的过程也是它走向完整的过程。<br> 神话描述的范例包括了捆仙锁、圣钉、世界之树的根须等现实世界神话，也包括存在于文学作品中的神话内容。</p><p>●魔幻本质<br> 具有“魔幻”这一本质作为描述的事物是具有魔法、奇幻、灵异、仙侠或玄幻背景的，它自有一套说法，完全脱离现实。<br> 某些效果可以压制或解除一些具有魔幻描述的效果。<br> 绝大多数具有“魔幻”描述的事物需要向主神购买，但某些具有此描述的能力可以在轮回小队成员满足一定前提的情况下自行修炼。<br> 魔幻描述的范例包括：墨绿披风、隐美的假面等</p><p>●特异本质<br> 具有“特异”这一本质作为描述的事物往往是用科学难以解释的事物；它们大多数都不符合一般观念中魔法或法术的定义。这些事物既有违科学，又并非魔幻。某些古老的、或极度科幻的技能是特异的。<br> 绝大多数具有“特异”描述的事物需要向主神购买，但某些具有此描述的能力可以在轮回小队成员满足一定前提的情况下自行修炼。<br> 特异描述的范例包括：死亡笔记、王气、康少校的核弹等</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
